con:mockService.con:onRequestScript:
import java.text.SimpleDateFormat

def sdf = new SimpleDateFormat("yyyyMMddHHmmss")
def now = sdf.format(new Date())
context.now = now

con:mockOperation.con:dispatchPath:
import com.eviware.soapui.support.XmlHolder
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlContext
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlValidator
import com.eviware.soapui.impl.wsdl.panels.mockoperation.WsdlMockRequestMessageExchange

synchronized(mockRequest.context.mockService){

mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation)
context.validationMessages = mh.getSchemaErrorsInRequest() ?: mh.getEmptyElementsInRequest() ?: null
if (context.validationMessages) {
	return "SOAP Exception"
}

def holder = new XmlHolder( mockRequest.requestContent )
holder.namespaces['soapenv'] = 'http://schemas.xmlsoap.org/soap/envelope/'
holder.namespaces['urn'] = 'urn:riv:itintegration:registry:1'
holder.namespaces['urn1'] = 'urn:riv:clinicalprocess:activityprescription:actoutcome:GetVaccinationHistoryResponder:2'
holder.namespaces['urn2'] = 'urn:riv:clinicalprocess:activityprescription:actoutcome:2'

def careUnitHSAid = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetVaccinationHistory/urn1:careUnitHSAid')
def patientId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetVaccinationHistory/urn1:patientId/urn2:id')
def patientIdType = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetVaccinationHistory/urn1:patientId/urn2:type')
def sourceSystemHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetVaccinationHistory/urn1:sourceSystemHSAId')

context.patientId = patientId
context.patientIdType = patientIdType
context.careUnitHSAid = careUnitHSAid
context.sourceSystemHSAId = sourceSystemHSAId

def responseName = "BasicResponse"
if (mockRequest.requestHeaders['x-mock-response'] != null){
	responseName = mockRequest.requestHeaders['x-mock-response'][0]
}
log.info("responseName: ${responseName}")
return responseName
}
